{
  "name": "ATS-Master CV Generator",
  "description": "A world-class CV generator that uses Gemini AI to analyze job descriptions, create a strategic mind map, and build a 100% ATS-optimized resume with tangible results and clean layout."
}

export interface CvData {
  personalInfo: {
    fullName: string;
    email: string;
    phone: string;
    linkedin: string;
    portfolio: string;
    location: string;
  };
  summary: string;
  skills: string[];
  experience: ExperienceItem[];
  education: EducationItem[];
  projects: ProjectItem[];
}

export interface ExperienceItem {
  id: string;
  role: string;
  company: string;
  duration: string;
  description: string[]; // Bullet points
}

export interface EducationItem {
  id: string;
  degree: string;
  institution: string;
  year: string;
}

export interface ProjectItem {
  id: string;
  name: string;
  description: string;
  link?: string;
}

export interface MindMapNode {
  name: string;
  status: 'pending' | 'in-progress' | 'completed';
  children?: MindMapNode[];
  details?: string;
}

export interface AnalysisResult {
  score: number;
  missingInfo: string[];
  keywords: string[];
  mindMap: MindMapNode;
}

export enum AppStep {
  INPUT = 'INPUT',
  ANALYZING = 'ANALYZING',
  MINDMAP = 'MINDMAP',
  BUILDING = 'BUILDING',
  PREVIEW = 'PREVIEW'
}

export interface Message {
  role: 'user' | 'ai';
  content: string;
}

import { GoogleGenAI, Type } from "@google/genai";
import { CvData, AnalysisResult, MindMapNode } from '../types';

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const MODEL_NAME = 'gemini-2.5-flash-latest'; // Fast model for interactive parts

export const analyzeJobAndProfile = async (
  jobDescription: string,
  currentCvText: string
): Promise<AnalysisResult> => {
  const prompt = `
    You are an expert ATS Resume Auditor. Analyze the following Job Description (JD) and User's Current CV/Profile Information.

    Goal: Identify gaps to reach a 100% ATS match score.

    Job Description:
    ${jobDescription}

    User Profile/CV:
    ${currentCvText}

    Return a JSON object with:
    1. 'score': An estimated current ATS match score (0-100).
    2. 'missingInfo': A list of critical missing information (e.g., specific skills mentioned in JD but missing in CV, missing metrics, missing portfolio links).
    3. 'keywords': Top 10 ATS keywords found in the JD.
    4. 'mindMap': A hierarchical plan (tree structure) to build the perfect CV. The root node should be "100% ATS CV". Children should be the steps: "Strategy", "Content Optimization", "Formatting". Under "Content Optimization", include specific missing sections or skills to fix.
  `;

  const response = await ai.models.generateContent({
    model: MODEL_NAME,
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          score: { type: Type.NUMBER },
          missingInfo: { type: Type.ARRAY, items: { type: Type.STRING } },
          keywords: { type: Type.ARRAY, items: { type: Type.STRING } },
          mindMap: {
            type: Type.OBJECT,
            properties: {
              name: { type: Type.STRING },
              status: { type: Type.STRING, enum: ['pending', 'in-progress', 'completed'] },
              details: { type: Type.STRING },
              children: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    name: { type: Type.STRING },
                    status: { type: Type.STRING },
                    details: { type: Type.STRING },
                    children: { type: Type.ARRAY, items: {type: Type.OBJECT, properties: {}, additionalProperties: true} } // Recurse roughly
                  }
                }
              }
            },
            required: ['name', 'status', 'children']
          }
        },
        required: ['score', 'missingInfo', 'keywords', 'mindMap']
      }
    }
  });

  return JSON.parse(response.text || '{}') as AnalysisResult;
};

export const generateCvSection = async (
  section: 'summary' | 'experience' | 'skills' | 'projects',
  jobDescription: string,
  userContext: string,
  extraUserInputs: string
): Promise<any> => {
  let schema;
  let promptDetails = "";

  if (section === 'summary') {
    promptDetails = "Write a powerful professional summary (max 4 lines) tailored to the JD. Highlight specific achievements and alignment with the role.";
    schema = { type: Type.STRING };
  } else if (section === 'skills') {
    promptDetails = "List top 15-20 technical and soft skills, strictly matching JD keywords. Group them logically if needed, but return a flat list for now.";
    schema = { type: Type.ARRAY, items: { type: Type.STRING } };
  } else if (section === 'experience') {
    promptDetails = "Refine the work experience. Use the XYZ formula (Accomplished [X] as measured by [Y], by doing [Z]). Focus on outcomes, not duties. Add strong verbs and metrics.";
    schema = {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          id: { type: Type.STRING },
          role: { type: Type.STRING },
          company: { type: Type.STRING },
          duration: { type: Type.STRING },
          description: { type: Type.ARRAY, items: { type: Type.STRING } }
        },
        required: ['role', 'company', 'duration', 'description']
      }
    };
  } else if (section === 'projects') {
    promptDetails = "List relevant projects that prove skills mentioned in JD. Include name, concise description with tech stack used.";
    schema = {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          id: { type: Type.STRING },
          name: { type: Type.STRING },
          description: { type: Type.STRING },
          link: { type: Type.STRING }
        }
      }
    };
  }

  const prompt = `
    Job Description: ${jobDescription}
    User Context: ${userContext}
    User Answers to Missing Info: ${extraUserInputs}

    Task: ${promptDetails}
  `;

  const response = await ai.models.generateContent({
    model: MODEL_NAME,
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: schema
    }
  });

  if (section === 'summary') return JSON.parse(response.text || '""');
  return JSON.parse(response.text || '[]');
};

export const chatWithCoach = async (
  history: {role: 'user' | 'model', parts: [{ text: string }]} [],
  message: string,
  context: string
) => {
  const chat = ai.chats.create({
    model: MODEL_NAME,
    history: [
      {
        role: 'user',
        parts: [{ text: `System Context: You are an expert Career Coach helping the user build a CV. Here is the background info: ${context}. Be concise, helpful, and focused on gathering missing info for the CV.` }]
      },
      {
        role: 'model',
        parts: [{ text: "Understood. I am ready to help refine the CV and ask clarifying questions." }]
      },
      ...history
    ]
  });

  const result = await chat.sendMessage({ message });
  return result.text;
};

import React, { useEffect, useRef } from 'react';
import * as d3 from 'd3';
import { MindMapNode } from '../types';

interface MindMapProps {
  data: MindMapNode;
}

export const MindMap: React.FC<MindMapProps> = ({ data }) => {
  const svgRef = useRef<SVGSVGElement>(null);

  useEffect(() => {
    if (!data || !svgRef.current) return;

    const width = 800;
    const height = 400;

    // Clear previous svg content
    d3.select(svgRef.current).selectAll("*").remove();

    const svg = d3.select(svgRef.current)
      .attr("viewBox", [0, 0, width, height])
      .style("font", "12px sans-serif")
      .style("user-select", "none");

    const root = d3.hierarchy(data);
    const treeLayout = d3.tree<MindMapNode>().size([height - 40, width - 160]);

    treeLayout(root);

    const g = svg.append("g")
      .attr("transform", "translate(80,20)");

    const link = g.selectAll(".link")
      .data(root.links())
      .join("path")
      .attr("class", "link")
      .attr("d", d3.linkHorizontal<any, any>()
          .x(d => d.y)
          .y(d => d.x))
      .attr("fill", "none")
      .attr("stroke", "#555")
      .attr("stroke-opacity", 0.4)
      .attr("stroke-width", 1.5);

    const node = g.selectAll(".node")
      .data(root.descendants())
      .join("g")
      .attr("class", d => `node ${d.children ? "node--internal" : "node--leaf"}`)
      .attr("transform", d => `translate(${d.y},${d.x})`);

    node.append("circle")
      .attr("r", 6)
      .attr("fill", d => d.data.status === 'completed' ? "#10b981" : d.data.status === 'in-progress' ? "#f59e0b" : "#9ca3af")
      .attr("stroke", "#fff")
      .attr("stroke-width", 2);

    node.append("text")
      .attr("dy", "0.31em")
      .attr("x", d => d.children ? -8 : 8)
      .attr("text-anchor", d => d.children ? "end" : "start")
      .text(d => d.data.name)
      .clone(true).lower()
      .attr("stroke", "white")
      .attr("stroke-width", 3);

  }, [data]);

  return (
    <div className="w-full overflow-x-auto bg-slate-50 rounded-lg border border-slate-200 p-4 shadow-sm">
      <h3 className="text-sm font-semibold text-slate-500 mb-2 uppercase tracking-wide">Strategy Mind Map</h3>
      <svg ref={svgRef} className="w-full h-auto min-w-[600px]"></svg>
    </div>
  );
};

